interface RateLimitConfig {
  maxTokens: number;        // Burst capacity (max tokens in bucket)
  refillRate: number;       // Tokens added per second
  refillInterval?: number;  // Interval in milliseconds (default 1000ms for per-second)
}

interface RateLimitResult {
  allowed: boolean;
  tokensRemaining: number;
  retryAfter?: number;     // Milliseconds to wait before retrying
}

class RateLimiter {
  private buckets: Map<string, {
    tokens: number;
    lastRefill: number;
  }> = new Map();

  private config: Required<RateLimitConfig>;

  constructor(config: RateLimitConfig) {
    this.config = {
      maxTokens: config.maxTokens,
      refillRate: config.refillRate,
      refillInterval: config.refillInterval ?? 1000,
    };
  }

  private refillBucket(userId: string): void {
    const now = Date.now();
    const bucket = this.buckets.get(userId);

    if (!bucket) {
      this.buckets.set(userId, {
        tokens: this.config.maxTokens,
        lastRefill: now,
      });
      return;
    }

    const timePassed = now - bucket.lastRefill;
    const tokensToAdd = (timePassed / this.config.refillInterval) * this.config.refillRate;

    bucket.tokens = Math.min(this.config.maxTokens, bucket.tokens + tokensToAdd);
